// src/views/user/MyProfile/composables/useProfileData.js
import { ref, onMounted } from 'vue'
import { profile } from '@/api/profile'
import { showToast } from '@/components/ToastMessage'
import store from '@/store'

export function useProfileData() {
  const resumeData = ref({
    avatar: '',
    name: '',
    phone: '',
    email: '',
    location: '',
    gender: '',
    jobStatus: '',
    expectedSalary: '',
    bio: '',
    birth_date: null,
    created_at: '',
    updated_at: ''
  })

  const loading = ref(false)
  const error = ref(null)

  const fetchInitialData = async () => {
    loading.value = true
    error.value = null
    try {
      const response = await profile.getBasicInfo()
      console.log('Profile response:', response)

      if (response.data) {
        const mappedData = {
          ...response.data,
          bio: response.data.personal_summary,
          gender: response.data.gender || ''
        }

        resumeData.value = {
          ...resumeData.value,
          ...mappedData
        }
      } else {
        throw new Error('获取资料失败：无数据返回')
      }
    } catch (err) {
      console.error('获取用户资料失败:', err)
      error.value = err.message || '获取用户资料失败'
      showToast(error.value, 'error')
    } finally {
      loading.value = false
    }
  }

  const updateResumeData = async (data) => {
    loading.value = true
    error.value = null
    try {
      if (Object.keys(data).length === 1 && 'avatar' in data) {
        resumeData.value = {
          ...resumeData.value,
          avatar: data.avatar
        }
        return true
      }

      const updateData = {
        name: data.name || '',
        phone: data.phone || '',
        email: data.email || '',
        location: data.location || '',
        gender: data.gender || '',
        personal_summary: data.bio || '',
        birth_date: data.birth_date || null,
        jobStatus: data.jobStatus || '',
        expectedSalary: data.expectedSalary || ''
      }

      Object.keys(updateData).forEach(key => {
        if (!updateData[key]) {
          delete updateData[key]
        }
      })

      console.log('Update data:', updateData)

      const response = await profile.updateBasicInfo(updateData)
      console.log('Update response:', response)

      if (response?.data) {
        resumeData.value = {
          ...resumeData.value,
          ...response.data,
          bio: response.data.personal_summary,
          gender: response.data.gender
        }

        await store.dispatch('fetchUserInfo')

        showToast('更新成功', 'success')
        return true
      }

      throw new Error(response?.message || '更新失败，请稍后重试')
    } catch (err) {
      console.error('更新用户资料失败:', err)
      error.value = err.message || '更新用户资料失败'
      showToast(error.value, 'error')
      return false
    } finally {
      loading.value = false
    }
  }

  onMounted(() => {
    fetchInitialData()
  })

  return {
    resumeData,
    loading,
    error,
    fetchInitialData,
    updateResumeData
  }
}
